args.sparql:
SELECT ?person WHERE {
  ?person p:P39 ?office_statement .
  ?office_statement ps:P39 wd:Q641589 .
  ?office_statement pq:P580 ?start .
} ORDER BY ASC(?start) LIMIT 1

SELECT ?office ?officeLabel WHERE {
  wd:Q333994 p:P39 ?officeStatement .
  ?officeStatement ps:P39 ?office .
  ?office rdfs:label ?officeLabel .
  FILTER(LANG(?officeLabel) = 'en')
}

SELECT ?person ?name WHERE {
  ?person p:P39 ?office_statement;
          rdfs:label ?name.
  ?office_statement ps:P39 wd:Q641589;
                 pq:P580 ?start.
  FILTER(LANG(?name) = 'en')
} ORDER BY ASC(?start)
LIMIT 1
